import type { ChatMessage, ContentBlock, TextBlock, ImageBlock, HtmlBlock, ToolCallBlock } from '../types/message'

export type ViewMode = 'normal' | 'turn' | 'outline'

export interface ConversationTurn {
  id: string
  index: number
  userMessage: ChatMessage
  assistantMessages: ChatMessage[]
}

export function truncate(text: string, maxLen: number): string {
  if (text.length <= maxLen) return text
  return text.substring(0, maxLen - 1) + '\u2026'
}

function firstLine(text: string): string {
  const idx = text.indexOf('\n')
  return idx === -1 ? text : text.substring(0, idx)
}

function textBlockSummary(block: TextBlock): string {
  return firstLine(block.content)
}

function imageBlockSummary(_block: ImageBlock): string {
  void _block
  return '[image]'
}

function htmlBlockSummary(block: HtmlBlock): string {
  return block.title ? `[HTML: ${block.title}]` : '[HTML]'
}

function getUserBlockSummary(block: ContentBlock): string | null {
  switch (block.type) {
    case 'text':
      return textBlockSummary(block)
    case 'image':
      return imageBlockSummary(block)
    case 'html':
      return htmlBlockSummary(block)
    default:
      return null
  }
}

export function getUserSummary(msg: ChatMessage): string {
  const parts: string[] = []
  for (const block of msg.blocks) {
    const s = getUserBlockSummary(block)
    if (s !== null) parts.push(s)
  }
  return truncate(parts.join(' \u00B7 '), 80)
}

export function getAgentSummary(messages: ChatMessage[]): string {
  const toolCounts: Record<string, number> = {}
  let textSummary: string | null = null
  let imageCount = 0
  let htmlCount = 0

  for (const msg of messages) {
    for (const block of msg.blocks) {
      switch (block.type) {
        case 'tool_call': {
          const name = (block as ToolCallBlock).toolName
          toolCounts[name] = (toolCounts[name] || 0) + 1
          break
        }
        case 'text': {
          if (textSummary === null) {
            textSummary = firstLine((block as TextBlock).content)
          }
          break
        }
        case 'image': {
          imageCount++
          break
        }
        case 'html': {
          htmlCount++
          break
        }
        default:
          break
      }
    }
  }

  const parts: string[] = []

  const toolParts = Object.entries(toolCounts)
    .sort(([a], [b]) => a.localeCompare(b))
    .map(([name, count]) => count > 1 ? `${name} x${count}` : name)
  if (toolParts.length > 0) {
    parts.push(toolParts.join(', '))
  }

  if (textSummary !== null) {
    parts.push(truncate(textSummary, 80))
  }

  if (imageCount > 0) {
    parts.push(`[${imageCount} image${imageCount > 1 ? 's' : ''}]`)
  }
  if (htmlCount > 0) {
    parts.push(`[${htmlCount} HTML${htmlCount > 1 ? 's' : ''}]`)
  }

  return parts.join(' \u00B7 ')
}

export function groupByTurns(messages: ChatMessage[]): ConversationTurn[] {
  const turns: ConversationTurn[] = []
  let currentUser: ChatMessage | null = null
  let assistantMessages: ChatMessage[] = []

  for (const msg of messages) {
    if (msg.role === 'system') continue

    if (msg.role === 'user') {
      if (currentUser !== null) {
        turns.push({
          id: currentUser.id,
          index: turns.length + 1,
          userMessage: currentUser,
          assistantMessages,
        })
      }
      currentUser = msg
      assistantMessages = []
    } else if (msg.role === 'assistant') {
      assistantMessages.push(msg)
    }
  }

  if (currentUser !== null) {
    turns.push({
      id: currentUser.id,
      index: turns.length + 1,
      userMessage: currentUser,
      assistantMessages,
    })
  }

  return turns
}

import { useState } from 'react'

interface TokenUsageRingProps {
  usedTokens: number
  contextWindowSize: number
  inputTokens: number
  outputTokens: number
  cacheReadTokens: number
  totalCost: number
}

export function interpolateColor(hex1: string, hex2: string, t: number): string {
  const r1 = parseInt(hex1.slice(1, 3), 16)
  const g1 = parseInt(hex1.slice(3, 5), 16)
  const b1 = parseInt(hex1.slice(5, 7), 16)
  const r2 = parseInt(hex2.slice(1, 3), 16)
  const g2 = parseInt(hex2.slice(3, 5), 16)
  const b2 = parseInt(hex2.slice(5, 7), 16)
  const r = Math.round(r1 + (r2 - r1) * t)
  const g = Math.round(g1 + (g2 - g1) * t)
  const b = Math.round(b1 + (b2 - b1) * t)
  return `#${r.toString(16).padStart(2, '0')}${g.toString(16).padStart(2, '0')}${b.toString(16).padStart(2, '0')}`
}

export function formatTokens(n: number): string {
  if (n >= 1000) {
    return `${(n / 1000).toFixed(1)}K`
  }
  return String(n)
}

export function getFillColor(pct: number): string {
  if (pct < 0.5) {
    return '#22c55e'
  }
  if (pct < 0.75) {
    const t = (pct - 0.5) / 0.25
    return interpolateColor('#22c55e', '#eab308', t)
  }
  if (pct < 0.9) {
    const t = (pct - 0.75) / 0.15
    return interpolateColor('#eab308', '#f97316', t)
  }
  const t = Math.min(1, (pct - 0.9) / 0.1)
  return interpolateColor('#f97316', '#ef4444', t)
}

export function TokenUsageRing({
  usedTokens,
  contextWindowSize,
  inputTokens,
  outputTokens,
  cacheReadTokens,
  totalCost,
}: TokenUsageRingProps) {
  const [hovered, setHovered] = useState(false)

  const rawPct = contextWindowSize > 0 ? usedTokens / contextWindowSize : 0
  const pct = Math.max(0, Math.min(1, rawPct))
  const percent = Math.round(pct * 100)

  const strokeWidth = 4
  const size = 36
  const radius = (size - strokeWidth) / 2
  const circumference = 2 * Math.PI * radius
  const dashOffset = circumference * (1 - pct)

  const fillColor = getFillColor(pct)
  const isCritical = pct >= 0.9

  const remaining = contextWindowSize - usedTokens

  const tooltipRows: Array<{ label: string; value: string } | 'divider'> = [
    { label: 'Input:', value: formatTokens(inputTokens) },
    { label: 'Output:', value: formatTokens(outputTokens) },
    { label: 'Cache Read:', value: formatTokens(cacheReadTokens) },
    'divider',
    { label: 'Used:', value: formatTokens(usedTokens) },
    { label: 'Window:', value: formatTokens(contextWindowSize) },
    { label: 'Remaining:', value: formatTokens(remaining) },
    { label: 'Cost:', value: `$${totalCost.toFixed(2)}` },
  ]

  return (
    <div
      style={{ position: 'relative', display: 'inline-flex' }}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
    >
      <style>{`
        @keyframes pulse-critical {
          0%, 100% { opacity: 1; }
          50% { opacity: 0.5; }
        }
      `}</style>
      <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
        <circle
          cx={size / 2}
          cy={size / 2}
          r={radius}
          fill="none"
          stroke="#e5e7eb"
          strokeWidth={strokeWidth}
        />
        <circle
          cx={size / 2}
          cy={size / 2}
          r={radius}
          fill="none"
          stroke={fillColor}
          strokeWidth={strokeWidth}
          strokeLinecap="round"
          strokeDasharray={circumference}
          strokeDashoffset={dashOffset}
          transform={`rotate(-90 ${size / 2} ${size / 2})`}
          style={{
            transition: 'stroke-dashoffset 0.6s cubic-bezier(0.4, 0, 0.2, 1)',
            ...(isCritical ? { animation: 'pulse-critical 1s ease-in-out infinite' } : {}),
          }}
        />
        <text
          x={size / 2}
          y={size / 2}
          textAnchor="middle"
          dominantBaseline="central"
          fontSize={9}
          fontWeight={600}
          fill="#374151"
        >
          {percent}
        </text>
      </svg>
      <div
        data-tooltip
        style={{
          position: 'absolute',
          top: '100%',
          left: '50%',
          transform: 'translateX(-50%)',
          marginTop: 6,
          background: '#1a1a2e',
          borderRadius: 6,
          padding: '8px 10px',
          fontSize: 11,
          color: '#fff',
          whiteSpace: 'nowrap',
          opacity: hovered ? 1 : 0,
          transition: 'opacity 0.2s',
          pointerEvents: 'none',
          zIndex: 50,
        }}
      >
        {tooltipRows.map((row, i) =>
          row === 'divider' ? (
            <div
              key={i}
              style={{
                borderTop: '1px solid rgba(255,255,255,0.15)',
                margin: '4px 0',
              }}
            />
          ) : (
            <div
              key={i}
              style={{ display: 'flex', justifyContent: 'space-between', gap: 12 }}
            >
              <span style={{ color: '#aaa' }}>{row.label}</span>
              <span>{row.value}</span>
            </div>
          ),
        )}
      </div>
    </div>
  )
}

import { useState } from 'react'
import type { ActionBlock } from '../types/message'

interface ActionBlockRendererProps {
  block: ActionBlock
  onRespond: (response: Record<string, unknown>) => void
}

export function ActionBlockRenderer({ block, onRespond }: ActionBlockRendererProps) {
  switch (block.actionType) {
    case 'select':
      return <SelectAction block={block} onRespond={onRespond} />
    case 'confirm':
      return <ConfirmAction block={block} onRespond={onRespond} />
    case 'input':
      return <InputAction block={block} onRespond={onRespond} />
  }
}

function SelectAction({ block, onRespond }: ActionBlockRendererProps) {
  const [selected, setSelected] = useState<string | null>(null)

  if (!block.options || block.options.length === 0) return null

  return (
    <div className="rounded-lg border border-amber-300 bg-amber-50 p-3">
      <div className="mb-2 text-sm font-medium text-amber-800">{block.label}</div>
      <div className="flex flex-wrap gap-2">
        {block.options.map((opt) => (
          <button
            key={opt.id}
            onClick={() => {
              setSelected(opt.id)
              onRespond({ value: opt.label })
            }}
            className={`rounded-lg border px-4 py-2 text-sm transition-colors ${
              selected === opt.id
                ? 'border-amber-500 bg-amber-600 text-white'
                : 'border-gray-300 bg-white text-gray-700 hover:border-gray-400 hover:bg-gray-50'
            }`}
          >
            {opt.label}
            {opt.description && (
              <span className="ml-1 text-xs opacity-60">- {opt.description}</span>
            )}
          </button>
        ))}
      </div>
    </div>
  )
}

function ConfirmAction({ block, onRespond }: ActionBlockRendererProps) {
  return (
    <div className="rounded-lg border border-amber-300 bg-amber-50 p-3">
      <div className="mb-2 text-sm font-medium text-amber-800">{block.label}</div>
      <div className="flex gap-2">
        <button
          onClick={() => onRespond({ confirmed: true })}
          className="rounded-lg bg-green-600 px-4 py-2 text-sm font-medium text-white hover:bg-green-500"
        >
          Confirm
        </button>
        <button
          onClick={() => onRespond({ cancelled: true as const })}
          className="rounded-lg bg-red-600 px-4 py-2 text-sm font-medium text-white hover:bg-red-500"
        >
          Cancel
        </button>
      </div>
    </div>
  )
}

function InputAction({ block, onRespond }: ActionBlockRendererProps) {
  const [value, setValue] = useState('')

  return (
    <div className="rounded-lg border border-amber-300 bg-amber-50 p-3">
      <div className="mb-2 text-sm font-medium text-amber-800">{block.label}</div>
      <div className="flex gap-2">
        <input
          type="text"
          value={value}
          onChange={(e) => setValue(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === 'Enter' && value.trim()) {
              onRespond({ value: value.trim() })
            }
          }}
          placeholder="Type your response..."
          className="flex-1 rounded-lg border border-gray-300 bg-white px-3 py-2 text-sm text-gray-900 placeholder-gray-400 focus:outline-none focus:ring-1 focus:ring-amber-500"
        />
        <button
          onClick={() => {
            if (value.trim()) onRespond({ value: value.trim() })
          }}
          disabled={!value.trim()}
          className="rounded-lg bg-amber-600 px-4 py-2 text-sm font-medium text-white hover:bg-amber-500 disabled:opacity-50"
        >
          Send
        </button>
      </div>
    </div>
  )
}

import { useEffect, useRef, useState, useCallback, useImperativeHandle, forwardRef } from 'react'
